import { useState, useEffect } from "react";
import "./InternalPortal.css";

function InternalPortal() {
  // ... all your existing state and functions remain EXACTLY THE SAME ...

  return (
    <div className="internal-portal-page">
      <h2>Internal Job Portal</h2>

      {/* ✅ FIXED: Added form wrapper for spacing + width matching */}
      <div className="internal-portal-form-wrapper">
        <div className="internal-portal-form-row">
          <input
            type="text"
            placeholder="Job Title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <input
            type="text"
            placeholder="Department"
            value={department}
            onChange={(e) => setDepartment(e.target.value)}
          />
          <input
            type="text"
            placeholder="Short Job Description"
            value={desc}
            onChange={(e) => setDesc(e.target.value)}
          />
          <button onClick={handlePost}>
            {editId ? "Update Job" : "Post Job"}
          </button>
        </div>
      </div>

      {/* ✅ Table stays exactly the same */}
      <table className="internal-portal-table">
        {/* ... your existing table code unchanged ... */}
      </table>
    </div>
  );
}

export default InternalPortal;
